import asyncio
import httpx
import json

async def test():
    # Use the same query format as anilist_client uses
    query = '''
    query (\$username: String, \$page: Int, \$perPage: Int) {
      Page(page: \$page, perPage: \$perPage) {
        pageInfo {
          total
          currentPage
          lastPage
          hasNextPage
          perPage
        }
        mediaList(userName: \$username, type: ANIME) {
          id
          status
          score(format: POINT_100)
          progress
          media {
            id
            title { romaji english }
            genres
            tags { id name rank }
            studios(isMain: true) { edges { node { id name isAnimationStudio } } }
            season
            seasonYear
            episodes
            meanScore
            popularity
            description(asHtml: false)
            coverImage { large }
            status
          }
        }
      }
    }
    '''
    async with httpx.AsyncClient() as client:
        resp = await client.post(
            'https://graphql.anilist.co',
            json={'query': query, 'variables': {'username': 'FateAnimeList', 'page': 1, 'perPage': 50}},
            headers={'Content-Type': 'application/json', 'Accept': 'application/json'}
        )
        print(f'Status: {resp.status_code}')
        print(f'Headers: {dict(resp.headers)}')
        try:
            data = resp.json()
            if 'errors' in data:
                print(f'Errors: {json.dumps(data[\"errors\"], indent=2)}')
            else:
                print(f'Page data: {json.dumps(data.get(\"data\", {}).get(\"Page\", {}), indent=2)[:500]}')
        except:
            print(f'Raw: {resp.text[:500]}')

asyncio.run(test())
